        .ok_or_else(|| ConfigError::MissingKey(key.to_string()))
}

fn get_u32(config: &HashMap<String, String>, key: &str) -> Result<u32, ConfigError> {
    let val = get_required(config, key)?;
    val.parse::<u32>().map_err(|_| ConfigError::InvalidValue {
        key: key.to_string(),
        value: val.to_string(),
    })
}

fn main() {
