        *counts.entry(word.to_lowercase()).or_insert(0) += 1;
    }
    let mut pairs: Vec<(String, usize)> = counts.into_iter().collect();
    pairs.sort_by(|a, b| b.1.cmp(&a.1).then(a.0.cmp(&b.0)));
    pairs.into_iter().take(n).map(|(w, _)| w).collect()
}

fn top_words(input: &str) -> String {
    // Parse first token as n, rest as text
    let mut parts = input.splitn(2, ' ');
    let n: usize = parts.next().unwrap_or("0").parse().unwrap_or(0);
    let text = parts.next().unwrap_or("");
    top_n_words(text, n).join(",")
}

use std::thread;

fn parallel_sum(numbers: Vec<i64>) -> i64 {
    let mid = numbers.len() / 2;
    let first_half = numbers[..mid].to_vec();
    let second_half = numbers[mid..].to_vec();

    // Spawn two threads with move closures; join and sum results
    let h1 = thread::spawn(move || -> i64 { 0 });
    let h2 = thread::spawn(move || -> i64 { 0 });

    h1.join().unwrap() + h2.join().unwrap()
}

fn sum_parallel(input: &str) -> i64 {
    let numbers: Vec<i64> = input.split_whitespace()
        .filter_map(|s| s.parse().ok())
        .collect();
    parallel_sum(numbers)
}

use std::sync::{Arc, Mutex};
use std::thread;

fn shared_counter(increments: u32) -> u32 {
    let counter = Arc::new(Mutex::new(0u32));
    let mut handles = vec![];

    for _ in 0..increments {
        let counter_clone = Arc::clone(&counter);
        let handle = thread::spawn(move || {
            // Lock the mutex and increment
        });
        handles.push(handle);
    }

    for h in handles { h.join().unwrap(); }
    *counter.lock().unwrap()
}

fn count_concurrent(input: &str) -> u32 {
    let n: u32 = input.trim().parse().unwrap_or(0);
    shared_counter(n)
}
